//! The wasm-bindgen perception entry ŌĆö a ZERO-COPY `PerceptionEngine` for the recon service + the
//! CF edge. Built only for `wasm32` (`#[cfg(target_arch = "wasm32")] pub mod wasm_bindings;` in
//! `lib.rs`). Models the distributed-inference pattern (a `#[wasm_bindgen]` struct owning its buffers
//! in wasm linear memory, host writes/reads via raw pointers), specialised for the perception hot
//! path.
//!
//! ## Zero-copy contract (no per-frame copy of the ~390KB RGB24 across the bindgen boundary)
//!
//! The engine OWNS the frame buffer and the tick output buffer in wasm linear memory:
//!   - `frame_ptr()` + `frame_capacity()` ŌĆö the host builds `new Uint8Array(memory.buffer,
//!     frame_ptr(), w*h*3)` ONCE and writes each RGB24 frame DIRECTLY into the engine's buffer
//!     (zero copy IN; no `&[u8]` frame argument exists on the hot path).
//!   - `observe(pts_s)` ŌĆö reads the in-place frame buffer (the engine knows w/h/stride from `new`),
//!     runs the SIMD-accelerated, gnosis-frf-gated, gnosis-antiqueue-paced pipeline with NO per-frame
//!     allocation (the frame `Vec` is MOVED in and back via `mem::take`, never reallocated/copied),
//!     and writes the packed `ConsciousTick` wire bytes into the engine's tick buffer.
//!   - `tick_ptr()` + `tick_len()` ŌĆö the host reads the packed tick via a view and forwards it
//!     straight onto the WS (zero copy OUT). `tick_json()` is a separate debug path (NOT the hot
//!     path).
//!
//! The PERCEPTION WINDOW is this engine instance: the EMA `BackgroundModel`, `Tracker`, `SceneModel`,
//! and the frf value-door + antiqueue corridor live in `PerceptionCore` and persist across
//! `observe()` calls. `dispose()` frees it (`free()` is generated by wasm-bindgen).
//!
//! Panic discipline (distributed-inference doctrine): the JS-exposed methods validate up front and
//! return `Result<_, JsError>` rather than panic ŌĆö a panic in a `&mut self` method poisons the engine
//! for the rest of the session under `panic = "abort"`.

use wasm_bindgen::prelude::*;

use crate::frame::Frame;
use crate::pipeline::{PerceptionCore, PerceptionOpts};

/// Initialise panic hooks once (better wasm panic messages). Idempotent.
#[wasm_bindgen(start)]
pub fn __te_init() {
    console_error_panic_hook::set_once();
}

/// Construction options for [`PerceptionEngine`], parsed from a small JSON object the host passes to
/// `new`. Hand-parsed (no serde) to keep the wasm dependency surface minimal ŌĆö the same discipline as
/// the relay wire. Unknown keys are ignored; absent keys take the [`PerceptionOpts`] defaults.
///
/// Recognised keys (all optional):
///   `staticCam` (bool), `cMax` (number), `objectPriorsJson` (string), `handReach` (number),
///   `maxImpulse` (number), `plateauWindow` (number), `worldW` (number), `worldD` (number),
///   `workNs` (number), `dispatchNs` (number), `sourceId` (string), `layerId` (string).
fn parse_opts(opts_json: &str, base: PerceptionOpts) -> PerceptionOpts {
    let mut o = base;
    let s = opts_json.trim();
    if s.is_empty() || s == "{}" {
        return o;
    }
    // Minimal tolerant scan: find `"key"` then the following primitive. Avoids a JSON dep; the host
    // controls this string (JSON.stringify of a small opts object), so the inputs are well-formed.
    let bytes = s.as_bytes();
    let find_after = |key: &str| -> Option<usize> {
        let pat = format!("\"{key}\"");
        let idx = s.find(&pat)?;
        let mut i = idx + pat.len();
        while i < bytes.len() && (bytes[i] == b' ' || bytes[i] == b':' || bytes[i] == b'\t') {
            i += 1;
        }
        Some(i)
    };
    let read_bool = |key: &str| -> Option<bool> {
        let i = find_after(key)?;
        if s[i..].starts_with("true") {
            Some(true)
        } else if s[i..].starts_with("false") {
            Some(false)
        } else {
            None
        }
    };
    let read_num = |key: &str| -> Option<f64> {
        let i = find_after(key)?;
        let rest = &s[i..];
        let end = rest
            .find(|c: char| !(c.is_ascii_digit() || c == '.' || c == '-' || c == '+' || c == 'e' || c == 'E'))
            .unwrap_or(rest.len());
        rest[..end].parse().ok()
    };
    let read_str = |key: &str| -> Option<String> {
        let i = find_after(key)?;
        let rest = &s[i..];
        if !rest.starts_with('"') {
            return None;
        }
        let inner = &rest[1..];
        let end = inner.find('"')?;
        Some(inner[..end].to_string())
    };

    if let Some(v) = read_bool("staticCam") {
        o.static_cam = v;
    }
    if let Some(v) = read_num("cMax") {
        o.c_max = Some(v as f32);
    }
    if let Some(v) = read_str("objectPriorsJson") {
        if !v.is_empty() {
            o.object_priors_json = Some(v);
        }
    }
    if let Some(v) = read_num("handReach") {
        o.hand_reach = Some(v as f32);
    }
    if let Some(v) = read_num("maxImpulse") {
        o.max_impulse = Some(v as f32);
    }
    if let Some(v) = read_num("plateauWindow") {
        o.plateau_window = Some(v as u32);
    }
    if let Some(v) = read_num("worldW") {
        o.world_w = v as f32;
    }
    if let Some(v) = read_num("worldD") {
        o.world_d = v as f32;
    }
    if let Some(v) = read_num("workNs") {
        o.work_ns = (v as u64).max(1);
    }
    if let Some(v) = read_num("dispatchNs") {
        o.dispatch_ns = v as u64;
    }
    if let Some(v) = read_str("sourceId") {
        o.source_id = v;
    }
    if let Some(v) = read_str("layerId") {
        o.layer_id = v;
    }
    o
}

/// The zero-copy perception engine. Owns the frame buffer + tick output buffer in wasm linear memory
/// and the durable [`PerceptionCore`] (EMA background + tracker + scene + frf/antiqueue governor).
#[wasm_bindgen]
pub struct PerceptionEngine {
    core: PerceptionCore,
    width: u32,
    height: u32,
    /// The frame staging buffer (capacity == width*height*3). The host writes RGB24 here in place.
    /// Owned here; MOVED into a `Frame` for `observe` via `mem::take` and moved back (no realloc).
    frame: Vec<u8>,
    /// The packed `ConsciousTick` output buffer. `observe` fills it; the host reads `tick_ptr/len`.
    tick: Vec<u8>,
    /// Monotonic frame index (the stream position; pts is supplied by the host per call).
    index: u64,
}

#[wasm_bindgen]
impl PerceptionEngine {
    /// Build a perception engine for frames of `width`x`height` RGB24 at `fps`, with options from
    /// `opts_json` (see [`parse_opts`]). Pre-allocates the frame buffer (zeroed) so `frame_ptr()` is
    /// valid before the first write, and the tick buffer.
    #[wasm_bindgen(constructor)]
    pub fn new(width: u32, height: u32, fps: f64, opts_json: &str) -> Result<PerceptionEngine, JsError> {
        if width == 0 || height == 0 {
            return Err(JsError::new("PerceptionEngine: width and height must be non-zero"));
        }
        let cap = (width as usize)
            .checked_mul(height as usize)
            .and_then(|n| n.checked_mul(3))
            .ok_or_else(|| JsError::new("PerceptionEngine: width*height*3 overflows"))?;
        let opts = parse_opts(opts_json, PerceptionOpts::default());
        let core = PerceptionCore::new(width, height, fps, &opts).map_err(|e| JsError::new(&e))?;
        Ok(PerceptionEngine {
            core,
            width,
            height,
            frame: vec![0u8; cap],
            // The tick wire is a 10-byte header + a JSON payload; reserve a comfortable initial size.
            tick: Vec::with_capacity(8192),
            index: 0,
        })
    }

    /// Pointer to the engine-owned RGB24 frame buffer in wasm linear memory. The host writes the
    /// frame here IN PLACE: `new Uint8Array(memory.buffer, frame_ptr(), frame_capacity())`. Zero copy.
    /// NOTE: re-read after any call that could grow linear memory; this buffer never reallocates
    /// across `observe`, but a wasm memory growth elsewhere can move `memory.buffer`'s backing.
    #[wasm_bindgen(js_name = framePtr)]
    pub fn frame_ptr(&self) -> *const u8 {
        self.frame.as_ptr()
    }

    /// Capacity of the frame buffer in bytes (== width*height*3). The host writes exactly this many.
    #[wasm_bindgen(js_name = frameCapacity)]
    pub fn frame_capacity(&self) -> usize {
        self.frame.len()
    }

    /// Perceive the frame currently in the engine's frame buffer at presentation time `pts_s`
    /// (host clock ŌĆö no wall-clock read in the lib). Runs the SIMD-accelerated, gnosis-frf
    /// value-door-gated, gnosis-antiqueue-paced pipeline with NO per-frame allocation (the frame
    /// `Vec` is moved in and back; no copy of the ~390KB payload), then writes the packed
    /// `ConsciousTick` wire bytes into the engine's tick buffer. Returns `tick_len()` for convenience.
    pub fn observe(&mut self, pts_s: f64) -> usize {
        // Move the staging buffer into a Frame (no copy: Vec ownership transfer), perceive, move back.
        let rgb = core::mem::take(&mut self.frame);
        let frame = Frame {
            index: self.index,
            pts_s,
            width: self.width,
            height: self.height,
            rgb,
        };
        let packed = self.core.observe_packed(&frame, pts_s);
        // Restore the staging buffer (still the same allocation; capacity preserved for the next
        // host write). `observe_packed` only borrowed `&frame`, so `frame.rgb` is intact.
        self.frame = frame.rgb;
        self.index += 1;

        // Fill the tick output buffer in place (clear + extend reuses its allocation across frames).
        self.tick.clear();
        self.tick.extend_from_slice(&packed);
        self.tick.len()
    }

    /// Pointer to the packed `ConsciousTick` wire bytes from the most recent [`Self::observe`]. The
    /// host reads `new Uint8Array(memory.buffer, tick_ptr(), tick_len())` and forwards it onto the
    /// WS. Zero copy OUT. Valid until the next `observe`.
    #[wasm_bindgen(js_name = tickPtr)]
    pub fn tick_ptr(&self) -> *const u8 {
        self.tick.as_ptr()
    }

    /// Length in bytes of the packed tick from the most recent [`Self::observe`].
    #[wasm_bindgen(js_name = tickLen)]
    pub fn tick_len(&self) -> usize {
        self.tick.len()
    }

    /// DEBUG path (NOT the hot path): the human-readable relay JSON for the LAST-perceived scene
    /// state. Does not advance the sequence. Allocates a String across the boundary ŌĆö avoid per frame.
    #[wasm_bindgen(js_name = tickJson)]
    pub fn tick_json(&self, pts_s: f64) -> String {
        self.core.relay_json(pts_s)
    }

    /// Number of fully-certified (Accept) entities in the current scene.
    pub fn accepted(&self) -> usize {
        self.core.accepted()
    }

    /// The next sequence number that will be stamped onto a tick.
    pub fn sequence(&self) -> u32 {
        self.core.sequence()
    }

    /// Frame-to-frame motion energy in [0,1] from the most recent observe (the governor's signal).
    pub fn motion(&self) -> f32 {
        self.core.governor_tick().motion
    }

    /// The gnosis-frf value-door verdict for the per-frame stat work: "GREEN" (frf-parallel door) or
    /// "RED" (serial). On wasm this is the honest single-threaded verdict (telemetry, not a perf
    /// claim); the gnosis-antiqueue corridor governs streaming cadence/stability either way.
    #[wasm_bindgen(js_name = governorLight)]
    pub fn governor_light(&self) -> String {
        self.core.governor_tick().light.to_string()
    }

    /// antiqueue corridor: frame-events published so far this session (the cadence/throughput signal).
    pub fn published(&self) -> usize {
        self.core.governor_tick().published
    }

    /// antiqueue corridor: peak in-flight (the back-pressure signal the host can read to throttle).
    #[wasm_bindgen(js_name = peakInFlight)]
    pub fn peak_in_flight(&self) -> usize {
        self.core.governor_tick().peak_in_flight
    }

    /// Explicit dispose (wasm-bindgen also generates `free()`); kept for the host-shim symmetry with
    /// distributed-inference-host's `dispose()`.
    pub fn dispose(self) {
        // Dropped here; the engine's buffers + PerceptionCore are freed.
    }
}
